1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Simplest cases / processing fee ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums for single main items ---
15	  it.todo("single plain sword (newcomer first item) → base 100 + first-insurance 10 + fee 5 = 115 G");
16	  it.todo("single plain amulet (newcomer first item) → base 60 + first 6 + fee 5 = 71 G");
17	  it.todo("single plain staff (newcomer first item) → base 80 + first 8 + fee 5 = 93 G");
18	  it.todo("single plain potion (newcomer first item) → base 40 + first 4 + fee 5 = 49 G");
19	
20	  // --- Components and "building blocks of 3 alike" ---
21	  it.todo("2 runes → base 50 G (no block)");
22	  it.todo("3 runes → base 60 G (block applies)");
23	  it.todo("4 runes → base 100 G (no block — block requires exactly 3)");
24	  it.todo("7 runes → base 175 G (one block of 3 + 4 singles = 60 + 100)");
25	  it.todo("2 runes + 1 moonstone → base 75 G (no block: different types)");
26	  it.todo("3 runes + 3 moonstones → base 120 G (two separate blocks)");
27	
28	  // --- Item-specific modifiers (cursed, high enchantment) ---
29	  it.todo("cursed sword adds 50% surcharge on the cursed item's base premium");
30	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
31	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
32	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
33	
34	  // --- Policy-wide modifiers ---
35	  it.todo("loyalty discount applies for customer with exactly 2 years");
36	  it.todo("loyalty discount does NOT apply for customer with 1 year");
37	  it.todo("first insurance surcharge applies per item in a quote");
38	  it.todo("follow-up contract discount (15%) applies to second quote in scenario");
39	
40	  // --- Modifier scope on multi-item policies ---
41	  it.todo("cursed sword + plain amulet → cursed surcharge applies only to cursed item (210 G before further modifiers and fee)");
42	
43	  // --- Rounding ---
44	  it.todo("premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");
45	
46	  // --- Integration examples ---
47	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
48	  it.todo("long-standing customer (3yrs), 2nd quote, cursed sword (steel, ench 7) → premium 160 G; first-insurance still applies to each new sword");
49	
50	  // --- Quote error cases ---
51	  it.todo("quote with unknown item type → CLI exits non-zero, writes to stderr, no results to stdout");
52	
53	  // --- Claim: standard reimbursement ---
54	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (full minus 100 deductible)");
55	  it.todo("damage to a rune (insurance 250 G), damage 200 G → payout 100 G");
56	
57	  // --- Claim: enchantment threshold ---
58	  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
59	
60	  // --- Claim: dragon material ---
61	  it.todo("dragon sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");
62	
63	  // --- Claim: enchantment threshold vs dragon material ---
64	  it.todo("dragon sword, enchantment 9, damage 1000 G → payout 400 G (50% rule wins)");
65	  it.todo("dragon sword, enchantment exactly 8, damage 1000 G → payout 400 G (high-ench clause applies, then deductible)");
66	
67	  // --- Claim: deductible per damage event ---
68	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per damaged item)");
69	
70	  // --- Claim: multiple items of same type ---
71	  it.todo("two swords insured; dragon attack damages both → each damage entry treated separately with own deductible");
72	  it.todo("claim has more entries of a type than policy covers → CLI exits non-zero (claim rejected)");
73	
74	  // --- Claim: cap exhaustion ---
75	  it.todo("sword + amulet policy → insurance sum 1600 G, cap 3200 G");
76	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value; modifiers don't raise cap)");
77	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
78	  it.todo("sword insured; two successive claims of 1500 G → first 1400 G payout cap remaining 600; second 600 G payout cap remaining 0");
79	
80	  // --- Claim: rounding ---
81	  it.todo("payout calculation 350.5 G rounds DOWN to 350 G");
82	
83	  // --- Claim error cases ---
84	  it.todo("claim references item not in policy → CLI exits non-zero, stderr");
85	  it.todo("claim references item with unknown type → CLI exits non-zero, stderr");
86	  it.todo("claim has damage with amount: -200 → CLI exits non-zero, stderr");
87	});
